const items = $input.all();
const linkedinAccounts = [];

function extractAccounts(data) {
  if (Array.isArray(data)) return data;
  if (data && typeof data === 'object') {
    if (data.platform) return [data];
    for (const key of ['data', 'accounts', 'results', 'items']) {
      if (Array.isArray(data[key])) return data[key];
    }
    for (const value of Object.values(data)) {
      if (Array.isArray(value)) return value;
    }
  }
  return [];
}

for (const item of items) {
  const rawAccounts = extractAccounts(item.json);
  for (const acc of rawAccounts) {
    if (acc && acc.platform && typeof acc.platform === 'string') {
      if (acc.platform.toLowerCase() === 'linkedin') {
        linkedinAccounts.push({ json: acc });
      }
    }
  }
}
return linkedinAccounts;

const accounts = $('Filter LinkedIn Accounts').all();
const posts = $('Fetch Recent Posts').all();
const results = [];
for (const acc of accounts) {
  const accountId = acc.json.accountId;
  for (const post of posts) {
    results.push({
      json: {
        accountId: accountId,
        postId: post.json.post_id
      }
    });
  }
}
return results;

const items = $input.all();
const results = [];
for (const item of items) {
  const data = item.json;
  const postId = item.json.postId || (data.analytics && data.analytics[0] && data.analytics[0].postId) || data.postId;

  let metrics = {};
  if (data.metrics) {
    metrics = data.metrics;
  } else if (data.analytics && data.analytics[0] && data.analytics[0].metrics) {
    metrics = data.analytics[0].metrics;
  }

  if (postId) {
    results.push({
      json: {
        post_id: postId,
        impressions: metrics.impressions || metrics.IMPRESSION || 0,
        likes: metrics.likes || metrics.REACTION || 0,
        comments: metrics.comments || metrics.COMMENT || 0,
        shares: metrics.shares || metrics.RESHARE || 0,
        clicks: metrics.clicks || metrics.CLICK || 0,
        saves: metrics.saves || metrics.POST_SAVE || 0,
        sends: metrics.sends || metrics.POST_SEND || 0
      }
    });
  }
}
return results;
